const staticData = $getWorkflowStaticData('global');
const body = $input.first().json.body || $input.first().json;
const raw = String(body.phone || '').replace(/[^0-9]/g, '');
if (!raw) return [{ json: { ok: false } }];

if (!staticData.optedOut) staticData.optedOut = {};
if (!staticData.whatsappMessaged) staticData.whatsappMessaged = {};

// Markt-unabhaengig blockieren: mehrere normalisierte Formen merken.
const forms = new Set();
forms.add(raw);
if (raw.length === 11 && raw.startsWith('1')) forms.add(raw.slice(1)); // US national
if (raw.startsWith('49')) forms.add(raw.slice(2));                      // DE national
forms.add(raw.replace(/^0+/, ''));
const at = new Date().toISOString();
for (const f of forms) {
  if (!f) continue;
  staticData.optedOut[f] = { opted_out: true, at };
}
// Auch unter Markt-Keys sperren, damit Dedup sicher greift
const usNat = (raw.length === 11 && raw.startsWith('1')) ? raw.slice(1) : raw;
const deNat = raw.startsWith('49') ? raw.slice(2).replace(/^0+/, '') : raw.replace(/^0+/, '');
staticData.whatsappMessaged['US:' + usNat] = { opted_out: true, at };
staticData.whatsappMessaged['DE:' + deNat] = { opted_out: true, at };

return [{ json: { ok: true, phone: raw } }];

// DUAL-MARKT: USA (EN) + Deutschland (DE) gleichzeitig.
// Jeder Markt hat eigene Staedte, Branchen, Telefon-Praefix, Template und Sprache.
const staticData = $getWorkflowStaticData('global');
const cfg = staticData.config || {};

const MARKETS = {
  US: {
    market: 'US',
    regionCode: 'US',
    template: 'WHATSAPP_TEMPLATE_NAME_EN',
    lang: 'en',
    phonePrefix: '1',
    dailyCap: cfg.us_cap || 25,
    cities: cfg.us_cities || [
      'Savannah GA','Atlanta GA','Charlotte NC','Nashville TN','Memphis TN',
      'Jacksonville FL','Orlando FL','Tampa FL','Miami FL','Houston TX',
      'Laredo TX','Lubbock TX','Corpus Christi TX','Little Rock AR','Wichita KS',
      'Baton Rouge LA','Huntsville AL','Mobile AL','Fayetteville NC','Greenville SC'
    ],
    industries: cfg.us_industries || [
      'electrician','plumber','HVAC contractor','roofer','landscaper',
      'painter','handyman','cleaning service','pest control','concrete contractor',
      'fence contractor','tile installer','tree service','pool service','garage door repair'
    ]
  },
  DE: {
    market: 'DE',
    regionCode: 'DE',
    template: 'WHATSAPP_TEMPLATE_NAME_DE',
    lang: 'de',
    phonePrefix: '49',
    dailyCap: cfg.de_cap || 25,
    cities: cfg.de_cities || [
      'Hamburg','Muenchen','Koeln','Berlin','Frankfurt','Stuttgart',
      'Duesseldorf','Dortmund','Essen','Bremen','Hannover','Nuernberg',
      'Duisburg','Bochum','Wuppertal','Bielefeld','Bonn','Muenster',
      'Karlsruhe','Mannheim'
    ],
    industries: cfg.de_industries || [
      'Elektriker','Klempner','Sanitaer Heizung','Dachdecker','Maler',
      'Gartenbau','Reinigungsfirma','Schreiner','Fliesenleger','Hausmeisterservice',
      'Schluesseldienst','Umzugsfirma','Trockenbau','Bodenleger','Zaunbau'
    ]
  }
};

// Welche Maerkte sind aktiv? Default: beide.
const activeMarkets = cfg.markets || ['US','DE'];

const combos = [];
for (const mk of activeMarkets) {
  const M = MARKETS[mk];
  if (!M) continue;
  const used = new Set();
  let tries = 0;
  // 4 Kombos pro Markt -> mit je 20 Treffern reicht das fuer den Tages-Cap
  while (combos.filter(c => c.market === mk).length < 4 && tries < 50) {
    tries++;
    const c = M.cities[Math.floor(Math.random() * M.cities.length)];
    const i = M.industries[Math.floor(Math.random() * M.industries.length)];
    const key = mk + '|' + c + '|' + i;
    if (used.has(key)) continue;
    used.add(key);
    combos.push({
      market: M.market, regionCode: M.regionCode, template: M.template,
      lang: M.lang, phonePrefix: M.phonePrefix, dailyCap: M.dailyCap,
      city: c, industry: i
    });
  }
}

return combos.map(x => ({ json: x }));

// Lead-Scoring: bewertet jeden Lead 0-100 und vergibt Note A/B/C.
// Ziel: der erfahrene Cold-Caller bekommt die besten Leads zuerst.
function scoreLead(p) {
  const rating = p.rating || 0;
  const reviews = p.userRatingCount || 0;
  let s = 20; // Basis: kein Website + Telefon + aktiv

  // Reputation: Firmen die auf ihren Ruf achten investieren eher in eine Website
  if (rating >= 4.5) s += 30;
  else if (rating >= 4.0) s += 25;
  else if (rating >= 3.5) s += 12;
  else if (rating > 0) s += 5;
  else s += 10; // keine Bewertung = neue Firma, braucht oft alles inkl. Website

  // Bewertungs-Anzahl: Sweet-Spot = etabliert, inhabergefuehrt, erreichbar, zahlungsfaehig
  if (reviews >= 10 && reviews <= 150) s += 35;        // ideal fuer Cold Call
  else if (reviews > 150 && reviews <= 400) s += 22;   // groesser, evtl. Gatekeeper
  else if (reviews >= 5 && reviews < 10) s += 18;      // jung aber real
  else if (reviews > 400) s += 10;                     // zu gross, schwer erreichbar
  else s += 6;                                         // <5 sehr neu/unbewiesen

  return Math.min(s, 100);
}

const cfgItems = $('Set Config & Target').all();
const all = $input.all();
const scored = [];

for (let i = 0; i < all.length; i++) {
  const places = all[i].json.places || [];
  const cfg = (cfgItems[i] || cfgItems[0] || { json: {} }).json;
  for (const p of places) {
    if (p.websiteUri) continue;
    const phone = p.nationalPhoneNumber || '';
    if (!phone) continue;
    if (p.businessStatus && p.businessStatus !== 'OPERATIONAL') continue; // keine geschlossenen
    const score = scoreLead(p);
    const grade = score >= 75 ? 'A' : (score >= 55 ? 'B' : 'C');
    scored.push({ json: {
      business_name: p.displayName?.text || '',
      phone,
      industry: cfg.industry || '',
      city: cfg.city || '',
      market: cfg.market || 'US',
      template: cfg.template || 'WHATSAPP_TEMPLATE_NAME_EN',
      lang: cfg.lang || 'en',
      phonePrefix: cfg.phonePrefix || '1',
      dailyCap: cfg.dailyCap || 25,
      rating: p.rating || 0,
      reviews_count: p.userRatingCount || 0,
      place_id: p.id || '',
      address: p.formattedAddress || '',
      score,
      grade
    }});
  }
}

// Beste Leads zuerst
scored.sort((a, b) => b.json.score - a.json.score);
return scored;

const staticData = $getWorkflowStaticData('global');
if (!staticData.whatsappMessaged) staticData.whatsappMessaged = {};

// Telefon je nach Markt normalisieren -> eindeutiger Dedup-Key 'MARKT:ziffern'
function normalize(market, raw) {
  let d = String(raw || '').replace(/[^0-9]/g, '');
  if (market === 'DE') {
    // Deutschland: fuehrende 00/49 weg, dann fuehrende 0 weg (nationale Form)
    if (d.startsWith('0049')) d = d.slice(4);
    else if (d.startsWith('49') && d.length > 9) d = d.slice(2);
    d = d.replace(/^0+/, '');
    return d.length >= 6 && d.length <= 12 ? d : null;
  }
  // USA: auf 10 Stellen normalisieren
  if (d.length === 11 && d.startsWith('1')) d = d.slice(1);
  return d.length === 10 ? d : null;
}

// Pro-Markt-Zaehler, damit jeder Markt seinen eigenen Tages-Cap bekommt
const sentPerMarket = {};
const out = [];

for (const item of $input.all()) {
  const l = item.json;
  const market = l.market || 'US';
  const digits = normalize(market, l.phone);
  if (!digits) continue;
  const key = market + ':' + digits;
  if (staticData.whatsappMessaged[key]) continue;
  // Markt-unabhaengige Opt-Out-Sperre (STOP / kein WhatsApp)
  if (staticData.optedOut && (staticData.optedOut[digits] || staticData.optedOut[l.phonePrefix + digits])) continue;
  const cap = l.dailyCap || 25;
  sentPerMarket[market] = sentPerMarket[market] || 0;
  if (sentPerMarket[market] >= cap) continue;
  sentPerMarket[market]++;
  out.push({ json: { ...l, phone_digits: digits, dedup_key: key } });
}
return out;

const l = $input.first().json;

// WhatsApp braucht internationale Nummer ohne +.
// US: 1 + 10 Ziffern. DE: 49 + nationale Nummer (ohne fuehrende 0).
const prefix = l.phonePrefix || '1';
const wa_to = prefix + l.phone_digits;

// business_name wird als {{1}} Template-Variable verwendet
const business_name = l.business_name || (l.lang === 'de' ? 'Team' : 'there');

// Google Maps Link, damit Atakan/Caller die Firma vor dem Gespraech anschaut
const maps_url = l.place_id
  ? 'https://www.google.com/maps/search/?api=1&query=' + encodeURIComponent(business_name) + '&query_place_id=' + l.place_id
  : 'https://www.google.com/maps/search/?api=1&query=' + encodeURIComponent(business_name + ' ' + (l.city||''));

return [{ json: { ...l, wa_to, business_name, maps_url } }];

