const staticData = $getWorkflowStaticData('global');
const l = $('Generate Preview & Message').first().json;
const resp = $input.first().json || {};
const now = new Date();
const today = now.toISOString().slice(0,10);
const digits = l.phone_digits;
const market = l.market || 'US';
const key = l.dedup_key || (market + ':' + digits);

// Lesbarer Sende-Zeitpunkt fuer den Caller (Markt-Zeitzone)
const tz = market === 'DE' ? 'Europe/Berlin' : 'America/New_York';
let sentHuman = now.toISOString();
try {
  sentHuman = now.toLocaleString(market === 'DE' ? 'de-DE' : 'en-US', { timeZone: tz, dateStyle: 'short', timeStyle: 'short' });
} catch(e) {}

// Akzeptiert nur wenn Meta eine message id zurueckgibt.
// Fehlgeschlagen (Festnetz / kein WhatsApp) -> kein message id -> Meta berechnet nichts.
const accepted = !!(resp.messages && resp.messages[0] && resp.messages[0].id);

if (!staticData.whatsappMessaged) staticData.whatsappMessaged = {};
// Immer markieren, damit dieselbe Nummer nie erneut angeschrieben wird
staticData.whatsappMessaged[key] = { at: now.toISOString(), name: l.business_name, accepted, market };

if (!staticData.waDailyCosts) staticData.waDailyCosts = {};
if (!staticData.waDailyCosts[today]) staticData.waDailyCosts[today] = {};
if (!staticData.waDailyCosts[today][market]) staticData.waDailyCosts[today][market] = {count: 0, failed: 0, cost: 0};
const bucket = staticData.waDailyCosts[today][market];

if (accepted) {
  if (!staticData.waLeads) staticData.waLeads = [];
  staticData.waLeads.push({
    business_name: l.business_name,
    phone: l.phone,
    phone_digits: digits,
    market,
    industry: l.industry,
    city: l.city,
    address: l.address || '',
    rating: l.rating || 0,
    reviews_count: l.reviews_count || 0,
    place_id: l.place_id || '',
    maps_url: l.maps_url || '',
    score: l.score || 0,
    grade: l.grade || 'C',
    status: 'sent',
    sent_at: now.toISOString(),
    sent_human: sentHuman
  });
  if (staticData.waLeads.length > 1000) staticData.waLeads = staticData.waLeads.slice(-1000);

  bucket.count++;
  // US ~$0.025, DE Marketing ~$0.08 pro Nachricht
  const rate = market === 'DE' ? 0.08 : 0.025;
  bucket.cost = parseFloat((bucket.count * rate).toFixed(4));
} else {
  bucket.failed = (bucket.failed || 0) + 1;
}

return [{ json: { ...l, saved: true, accepted, sent_human: sentHuman, sent_at: now.toISOString(), date: today } }];

const staticData = $getWorkflowStaticData('global');
const today = new Date().toISOString().slice(0,10);
const dayData = (staticData.waDailyCosts || {})[today] || {};
const sent = $input.all();

const us = dayData.US || {count:0, failed:0, cost:0};
const de = dayData.DE || {count:0, failed:0, cost:0};
const totalCount = (us.count||0) + (de.count||0);
const totalCost = (us.cost||0) + (de.cost||0);

let text = 'WHATSAPP OUTREACH ABGESCHLOSSEN\n\n';
text += 'USA: ' + (us.count||0) + ' gesendet';
if (us.failed) text += ' | ' + us.failed + ' kein WhatsApp';
text += ' | ~$' + (us.cost||0).toFixed(2) + '\n';
text += 'DE:  ' + (de.count||0) + ' gesendet';
if (de.failed) text += ' | ' + de.failed + ' kein WhatsApp';
text += ' | ~$' + (de.cost||0).toFixed(2) + '\n';
text += '----\n';
text += 'Gesamt heute: ' + totalCount + ' Nachrichten | ~$' + totalCost.toFixed(2) + '\n\n';

const delivered = sent.filter(s => s.json.accepted);
if (delivered.length > 0) {
  text += 'Diese Runde zugestellt:\n';
  delivered.forEach(s => {
    const l = s.json;
    const flag = l.market === 'DE' ? 'DE' : 'US';
    text += '  [' + flag + '] ' + (l.business_name||'?') + ' (' + (l.city||'') + ') — ' + (l.sent_human||'') + '\n';
  });
}

return [{ json: { report_text: text } }];

// Nur erfolgreich zugestellte Leads kommen ins Google Sheet (1 Zeile pro Lead).
// Spalten muessen im Sheet exakt so heissen (Zeile 1):
// Datum | Gesendet | Markt | Firma | Branche | Stadt | Bewertung | Reviews | Adresse | Telefon | Maps | Note | Status | Notizen
const rows = [];
for (const item of $input.all()) {
  const l = item.json;
  if (!l.accepted) continue;
  rows.push({ json: {
    Datum: l.date || new Date().toISOString().slice(0,10),
    Gesendet: l.sent_human || '',
    Markt: l.market || 'US',
    Firma: l.business_name || '',
    Branche: l.industry || '',
    Stadt: l.city || '',
    Bewertung: l.rating || 0,
    Reviews: l.reviews_count || 0,
    Adresse: l.address || '',
    Telefon: l.phone || '',
    Maps: l.maps_url || '',
    Note: l.grade || 'C',
    Status: 'offen',
    Notizen: ''
  }});
}
return rows;

const staticData = $getWorkflowStaticData('global');
// Beste Leads zuerst (Note A oben), dann max 15 fuer den Cold-Caller
const leads = (staticData.waLeads || [])
  .slice()
  .sort((a, b) => (b.score || 0) - (a.score || 0))
  .slice(0, 15);
if (leads.length === 0) {
  return [{ json: { leads_text: 'Noch keine Leads. Starte mit /start.' } }];
}
let text = 'BESTE LEADS FUER COLD CALLS (Note A zuerst):\n\n';
leads.forEach((l, i) => {
  const flag = l.market === 'DE' ? 'DE' : 'US';
  text += '[' + (l.grade || 'C') + '] [' + flag + '] ' + (l.business_name || '?') + '\n';
  text += '   ' + (l.industry || '-') + ' | ' + (l.city || '-') + '\n';
  if (l.rating) text += '   ' + l.rating + ' Sterne (' + (l.reviews_count || 0) + ' Reviews)\n';
  if (l.address) text += '   ' + l.address + '\n';
  text += '   Anrufen: ' + (l.phone || '-') + '\n';
  if (l.sent_human) text += '   WhatsApp gesendet: ' + l.sent_human + '\n';
  if (l.maps_url) text += '   Maps: ' + l.maps_url + '\n';
  text += '\n';
});
return [{ json: { leads_text: text } }];

const staticData = $getWorkflowStaticData('global');
const q = $input.first().json.query || {};
let raw = String(q.phone || '').replace(/[^0-9]/g, '');
// Inbound von Meta kommt international (z.B. 1XXXXXXXXXX oder 49XXXXXXXXX).
// Wir matchen tolerant: Lead-Eintrag findet sich, wenn seine Ziffern am Ende passen.
const leads = staticData.waLeads || [];
let lead = leads.find(l => raw.endsWith(l.phone_digits)) ||
           leads.find(l => l.phone_digits && raw.includes(l.phone_digits)) || {};
return [{ json: {
  found: !!lead.business_name,
  business_name: lead.business_name || '',
  market: lead.market || '',
  industry: lead.industry || '',
  city: lead.city || '',
  address: lead.address || '',
  rating: lead.rating || '',
  reviews_count: lead.reviews_count || 0,
  maps_url: lead.maps_url || '',
  sent_human: lead.sent_human || '',
  phone: lead.phone || ''
} }];
